@page "/notifications"
@rendermode @(new InteractiveServerRenderMode(prerender: true))
@implements IDisposable
@inject NotificationsApp.Services.NotificationService NotificationService

<PageTitle>Notifications</PageTitle>

<h1>Notifications <span class="badge bg-primary">@_notifications.Count</span></h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in _notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-center">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<NotificationsApp.Services.Notification> _notifications = new();
    private CancellationTokenSource? _cts;
    private int _lastSeenId;

    protected override void OnInitialized()
    {
        // Load initial notifications during prerender AND interactive init.
        // This ensures the SSR HTML contains the data immediately.
        _notifications = NotificationService.GetNotifications();
        _lastSeenId = _notifications.Count > 0 ? _notifications.Max(n => n.Id) : 0;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender only fires in interactive mode (not during static SSR),
            // so this is safe to start the polling loop here.
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(5000, ct);
            }
            catch (OperationCanceledException)
            {
                break;
            }

            // Simulate a new notification arriving on each poll
            NotificationService.SimulateIncoming();

            var newer = NotificationService.GetNotificationsSince(_lastSeenId);
            if (newer.Count > 0)
            {
                _notifications.AddRange(newer);
                _lastSeenId = newer.Max(n => n.Id);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

